#include <bits/stdc++.h>
using namespace std;
int m,n,order[402],a[21][21],t[21][21],q[21][10000],last[21],sum[21],ans,len[21];
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    cin>>m>>n;
    for(int i=1;i<=m*n;i++)
    	cin>>order[i];
    for(int i=1;i<=n;i++)
    	for(int j=1;j<=m;j++)
    		cin>>a[i][j];
    for(int i=1;i<=n;i++)
    	for(int j=1;j<=m;j++)
    		cin>>t[i][j];
    for(int i=1;i<=n*m;i++){
    	int p=order[i];
    	sum[p]++;
    	for(int j=last[p]+1;;j++){
    		bool flag=true;
    		for(int k=j;k<j+t[p][sum[p]];k++)
    			if(q[a[p][sum[p]]][k]){
    				flag=false;
    				break;
				}
			if(flag){
				for(int k=j;k<j+t[p][sum[p]];k++)
    				q[a[p][sum[p]]][k]=p;
    			ans=max(ans,j+t[p][sum[p]]-1);
    			last[p]=j+t[p][sum[p]]-1;
    			//len[a[p][sum[p]]]=max(len[a[p][sum[p]]],j+t[p][sum[p]]-1);
    			break;
    		}
		}
	}
	/*for(int i=1;i<=m;i++){
		for(int j=1;j<=len[i];j++)
			cout<<q[i][j]<<' ';
		cout<<'\n';
	}*/
	cout<<ans;
    return 0;
}
